import { create } from 'zustand';
import type { Organization, Team, OrganizationMember, TeamMember, Profile } from '@/types';
import {
  MOCK_ORG,
  MOCK_TEAMS,
  MOCK_ORG_MEMBERS,
  MOCK_TEAM_MEMBERS,
  MOCK_PROFILES,
} from '@/lib/mock/data';

interface OrgState {
  organization: Organization | null;
  teams: Team[];
  members: OrganizationMember[];
  teamMembers: TeamMember[];
  profiles: Profile[];

  getTeam: (teamId: string) => Team | undefined;
  getTeamMembers: (teamId: string) => Profile[];
  getProfile: (userId: string) => Profile | undefined;
  getMemberRole: (userId: string) => OrganizationMember | undefined;
  getUserTeams: (userId: string) => Team[];
}

export const useOrgStore = create<OrgState>((set, get) => ({
  organization: MOCK_ORG,
  teams: MOCK_TEAMS,
  members: MOCK_ORG_MEMBERS,
  teamMembers: MOCK_TEAM_MEMBERS,
  profiles: MOCK_PROFILES,

  getTeam: (teamId) => get().teams.find((t) => t.id === teamId),

  getTeamMembers: (teamId) => {
    const memberIds = get()
      .teamMembers.filter((tm) => tm.team_id === teamId)
      .map((tm) => tm.user_id);
    return get().profiles.filter((p) => memberIds.includes(p.id));
  },

  getProfile: (userId) => get().profiles.find((p) => p.id === userId),

  getMemberRole: (userId) => get().members.find((m) => m.user_id === userId),

  getUserTeams: (userId) => {
    const teamIds = get()
      .teamMembers.filter((tm) => tm.user_id === userId)
      .map((tm) => tm.team_id);
    return get().teams.filter((t) => teamIds.includes(t.id));
  },
}));
