import { create } from 'zustand';
import type { Profile, OrgRole } from '@/types';
import { MOCK_PROFILES, MOCK_ORG_MEMBERS } from '@/lib/mock/data';

interface AuthState {
  user: Profile | null;
  role: OrgRole;
  isAuthenticated: boolean;
  isLoading: boolean;
  login: (email: string) => void;
  logout: () => void;
  switchUser: (userId: string) => void;
}

export const useAuthStore = create<AuthState>((set) => ({
  // Default: logged in as Arjun (Owner) for development
  user: MOCK_PROFILES[0],
  role: 'owner',
  isAuthenticated: true,
  isLoading: false,

  login: (email: string) => {
    const profile = MOCK_PROFILES.find((p) => p.email === email);
    if (profile) {
      const membership = MOCK_ORG_MEMBERS.find((m) => m.user_id === profile.id);
      set({
        user: profile,
        role: membership?.role ?? 'viewer',
        isAuthenticated: true,
      });
    }
  },

  logout: () => {
    set({
      user: null,
      role: 'viewer',
      isAuthenticated: false,
    });
  },

  // Dev helper: switch between users to test different roles
  switchUser: (userId: string) => {
    const profile = MOCK_PROFILES.find((p) => p.id === userId);
    if (profile) {
      const membership = MOCK_ORG_MEMBERS.find((m) => m.user_id === profile.id);
      set({
        user: profile,
        role: membership?.role ?? 'viewer',
        isAuthenticated: true,
      });
    }
  },
}));
